import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I create a new customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/create-customer.md","filePath":"guide/recipes/admin/create-customer.md","lastUpdated":1778912818000}'),i={name:"guide/recipes/admin/create-customer.md"};function n(s,e,l,c,d,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="how-do-i-create-a-new-customer" tabindex="-1">How do I create a new customer? <a class="header-anchor" href="#how-do-i-create-a-new-customer" aria-label="Permalink to &quot;How do I create a new customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong>, <strong>Infra Ops</strong>, or <strong>Account Manager</strong> (within your customer scope)</p></div><p>A new customer is the entry point for onboarding. It creates the customer record, the billing settings, and the initial Owner invitation in one flow.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Customers</strong> in the Admin Console sidebar.</li><li>Click <strong>New Customer</strong>.</li><li>Fill in: <ul><li><strong>Name</strong> and <strong>Legal name</strong>.</li><li><strong>Plan</strong> — pick from active published plans.</li><li><strong>Billing contact email</strong> — receives invoices.</li><li><strong>Owner email</strong> — the person who&#39;ll become Owner of this customer&#39;s portal.</li></ul></li><li>Click <strong>Create</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The customer appears in the table with status <strong>Active</strong>. The Owner receives an invitation email. Until they accept, you can resend or revoke the invitation from the customer detail page.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-tenant">How do I create a new tenant?</a></li><li><a href="./configure-customer-billing">How do I configure billing for a customer?</a></li></ul>',9)])])}const p=t(i,[["render",n]]);export{h as __pageData,p as default};
